-- Convert the audio lessons in the "CM School" modules of
-- "The Canto to Mando Blueprint - Advanced" to Listening Practice, keeping
-- titles. Same treatment as the Intermediate CM School conversions
-- (0069-0071): sentences from the CM School scripts with long lines split at
-- natural boundaries and trivial one-word replies omitted; pinyin
-- auto-generated (jieba + tone sandhi, one syllable per Han character —
-- Latin words like "Michelle"/"APP" carry no pinyin so the reveal aligns);
-- English from the scripts.
--
-- Idempotent + scoped: each statement only touches the still-audio lesson in
-- its matching CM School module, in that course.

-- Discussing Cultural Identity (16 sentences)
UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"977ad30a-f475-4664-9053-cba22ceaf1f3","order":0,"chinese":"作为在美国长大的华裔，","pinyin":"zuò wéi zài měi guó zhǎng dà de huá yì","english":"As a Chinese-American raised in the U.S. —","audioUrl":null},{"id":"53287848-4e27-4368-a5c3-50db01fbeef3","order":1,"chinese":"你有没有曾经觉得自己和别人不一样？","pinyin":"nǐ yǒu méi yǒu céng jīng jué de zì jǐ hé bié rén bù yí yàng","english":"have you ever felt like you were different from others?","audioUrl":null},{"id":"5e75bbf0-821e-4e81-a76b-a2516c1943be","order":2,"chinese":"有啊，尽管我在这里出生，","pinyin":"yǒu a jín guǎn wǒ zài zhè lǐ chū shēng","english":"Yeah, even though I was born here,","audioUrl":null},{"id":"c56b8e14-4223-44b6-9245-e21a8cf48be4","order":3,"chinese":"有时候我还是感觉自己被看成外来者。","pinyin":"yǒu shí hòu wǒ hái shì gǎn jué zì jǐ bèi kàn chéng wài lái zhě","english":"sometimes I still feel like I''m seen as an outsider.","audioUrl":null},{"id":"2372aec6-29dd-46f3-a6b1-21958cccbacf","order":4,"chinese":"所以我觉得很多华人为了融入主流社会，","pinyin":"suó yǐ wǒ jué de hěn duō huá rén wèi le róng rù zhǔ liú shè huì","english":"So, I feel like many Chinese people, in order to fit into mainstream society,","audioUrl":null},{"id":"df639c6f-a585-4713-a74c-218b49b97297","order":5,"chinese":"忽视了自己的文化、传统和语言。","pinyin":"hū shì le zì jǐ de wén huà chuán tǒng hé yǔ yán","english":"overlook their own culture, traditions, and language.","audioUrl":null},{"id":"23f3ec55-3569-4a7a-adc4-6a1d5e5e86ea","order":6,"chinese":"我小时候也有觉得说中文和过中国节日很奇怪，","pinyin":"wǒ xiǎo shí hòu yě yǒu jué de shuō zhōng wén hé guò zhōng guó jié rì hěn qí guài","english":"When I was young, I also thought speaking Chinese and celebrating Chinese festivals were strange,","audioUrl":null},{"id":"7e714385-1e07-4145-ace2-7322e7131e81","order":7,"chinese":"所以刻意不在同学面前展现自己的文化。","pinyin":"suó yǐ kè yì bù zài tóng xué miàn qián zhǎn xiàn zì jǐ de wén huà","english":"so I intentionally hid my culture in front of my classmates.","audioUrl":null},{"id":"7ed76110-7d55-486a-8172-fe3cf141a413","order":8,"chinese":"但有了孩子之后，","pinyin":"dàn yǒu le hái zi zhī hòu","english":"But after having kids,","audioUrl":null},{"id":"905c2057-9480-43ec-959d-038e611033cc","order":9,"chinese":"我更深刻地意识到文化认同的重要性。","pinyin":"wǒ gèng shēn kè dì yì shí dào wén huà rèn tóng de zhòng yào xìng","english":"I became more deeply aware of how important cultural identity is.","audioUrl":null},{"id":"314fd0db-f192-4eda-a569-03139a6ddd63","order":10,"chinese":"我希望他们能了解自己的根，","pinyin":"wǒ xī wàng tā men néng liáo jiě zì jǐ de gēn","english":"I hope they can understand their roots,","audioUrl":null},{"id":"3a1e8d81-1c5a-4db7-8226-77f2f99a852b","order":11,"chinese":"并且明白他们的文化和背景也是他们的一部分。","pinyin":"bìng qiě míng bái tā men de wén huà hé bèi jǐng yě shì tā men de yí bù fen","english":"and realize that their culture and background are part of who they are.","audioUrl":null},{"id":"c05f0ec7-6273-4569-8d42-3d7a9a40dc68","order":12,"chinese":"这其实是我们那个时代的文化冲突。","pinyin":"zhè qí shí shì wǒ men nà ge shí dài de wén huà chōng tū","english":"This is actually a cultural conflict from our generation.","audioUrl":null},{"id":"2cb95619-4d25-4c1c-b395-0652238f29e7","order":13,"chinese":"我们小时候会害怕被歧视。","pinyin":"wǒ men xiǎo shí hòu huì hài pà bèi qí shì","english":"When we were young, we were afraid of being discriminated against.","audioUrl":null},{"id":"7e83053c-4272-43e4-84cf-9d0a8126c9de","order":14,"chinese":"但现在的社会越来越提倡多元文化，","pinyin":"dàn xiàn zài de shè huì yuè lái yuè tí chàng duō yuán wén huà","english":"But now, society is increasingly promoting multiculturalism,","audioUrl":null},{"id":"70bb75cb-3f31-4cfd-9b8a-456618b1167d","order":15,"chinese":"希望我们的小孩不会因为自己的身份而面对偏见。","pinyin":"xī wàng wǒ men de xiǎo hái bú huì yīn wèi zì jǐ de shēn fèn ér miàn duì piān jiàn","english":"and I hope our kids won''t face prejudice because of their identity.","audioUrl":null}]}'::jsonb,
    "updated_at" = now()
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - advanced'
      AND m."title" ILIKE '%cm school%'
      AND m."title" ILIKE '%cultural identity%'
  );

-- Sharing my Chinese Learning Journey (13 sentences)
UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"10fe76bd-e8c2-4d27-a352-09a3198df8b0","order":0,"chinese":"听说你在学中文，你学了多久了？","pinyin":"tīng shuō nǐ zài xué zhōng wén nǐ xué le duō jiǔ le","english":"I heard you''re learning Chinese. How long have you been studying?","audioUrl":null},{"id":"a2c05fee-7c8f-4e6a-a2ac-01a2083bc920","order":1,"chinese":"我学了差不多四个月了。","pinyin":"wǒ xué le chà bù duō sì gè yuè le","english":"I''ve been studying for almost four months.","audioUrl":null},{"id":"03df382e-0856-4c2e-8323-c43f8c0df0ce","order":2,"chinese":"因为我工作上经常碰到说普通话的客户。","pinyin":"yīn wèi wǒ gōng zuò shàng jīng cháng pèng dào shuō pǔ tōng huà de kè hù","english":"Because I often encounter Mandarin-speaking clients at work.","audioUrl":null},{"id":"d27b80af-79e4-4c75-9c07-a2f4b4d8f1b7","order":3,"chinese":"他们看到我的样子就觉得我会说中文。","pinyin":"tā men kàn dào wǒ de yàng zi jiù jué de wǒ huì shuō zhōng wén","english":"They see my face and assume I speak Chinese.","audioUrl":null},{"id":"3a2bee4b-b1cb-4fc1-9e81-9b625a5822e1","order":4,"chinese":"我每次都觉得有点尴尬，因为我根本没办法回应。","pinyin":"wǒ měi cì dōu jué de yóu diǎn gān gà yīn wèi wǒ gēn běn méi bàn fǎ huí yìng","english":"I always feel a bit embarrassed because I can''t respond at all.","audioUrl":null},{"id":"e1a5f1a5-7c2d-4f80-bad4-3a56c2761e3d","order":5,"chinese":"那感觉一定很糟糕。","pinyin":"nà gǎn jué yí dìng hěn zāo gāo","english":"That must feel really bad.","audioUrl":null},{"id":"45d5bc98-e3d6-41b8-b07b-08a726bcd4c3","order":6,"chinese":"那现在怎么样了？进步明显吗？","pinyin":"nà xiàn zài zěn me yàng le jìn bù míng xiǎn ma","english":"How''s it going now? Have you made noticeable progress?","audioUrl":null},{"id":"878011e9-06a3-4049-8c59-8b0fee591c48","order":7,"chinese":"现在好多了！我开始不怕犯错，敢开口说，","pinyin":"xiàn zài hǎo duō le wǒ kāi shǐ bú pà fàn cuò gǎn kāi kǒu shuō","english":"It''s much better now! I''ve started not being afraid to make mistakes and I dare to speak up.","audioUrl":null},{"id":"73f212d6-81a3-4a2f-ae56-4e14185084e9","order":8,"chinese":"慢慢可以跟客户沟通了。","pinyin":"màn màn ké yǐ gēn kè hù gōu tōng le","english":"Little by little, I can communicate with clients.","audioUrl":null},{"id":"6874b167-6bb5-4c45-b818-9adf491fdae1","order":9,"chinese":"更重要的是，我在家庭聚会里听得懂岳父岳母在说什么了。","pinyin":"gèng zhòng yào de shì wǒ zài jiā tíng jù huì lǐ tīng dé dǒng yuè fù yuè mǔ zài shuō shén me le","english":"More importantly, I can understand what my in-laws are saying at family gatherings now.","audioUrl":null},{"id":"97a050c1-ebcc-4a15-a5bf-7082341e6d1c","order":10,"chinese":"大家不再需要为了我而特地说英语。","pinyin":"dà jiā bú zài xū yào wèi le wǒ ér tè dì shuō yīng yǔ","english":"No one needs to speak English just for me anymore.","audioUrl":null},{"id":"ede2b848-0e28-4d7a-aa50-ed867e415102","order":11,"chinese":"这段学习过程虽然艰难，","pinyin":"zhè duàn xué xí guò chéng suī rán jiān nán","english":"This learning process was tough,","audioUrl":null},{"id":"98547086-5c27-4857-ab49-7c460a7ed868","order":12,"chinese":"但看到自己能做得到这些，真的非常值得。","pinyin":"dàn kàn dào zì jǐ néng zuò dé dào zhè xiē zhēn de fēi cháng zhí dé","english":"but seeing myself accomplish these things, it''s really worth it.","audioUrl":null}]}'::jsonb,
    "updated_at" = now()
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - advanced'
      AND m."title" ILIKE '%cm school%'
      AND m."title" ILIKE '%learning journey%'
  );

-- Seeing a Doctor (28 sentences)
UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"f70e4cbf-cbac-4bd5-ad75-7095583d9912","order":0,"chinese":"你哪里不舒服？","pinyin":"nǐ ná lǐ bù shū fú","english":"Where are you feeling uncomfortable?","audioUrl":null},{"id":"29fd9f2f-84aa-49b1-8049-c00fe0c2dfa6","order":1,"chinese":"我的喉咙又干又痒，老是咳嗽。","pinyin":"wǒ de hóu lóng yòu gān yòu yǎng lǎo shì ké sou","english":"My throat is dry and itchy, and I keep coughing.","audioUrl":null},{"id":"f40d9ad9-9862-4673-921a-cf9f27f284a5","order":2,"chinese":"还有头疼和拉肚子。","pinyin":"hái yǒu tóu téng hé lā dù zǐ","english":"I also have a headache and diarrhea.","audioUrl":null},{"id":"0abd9d61-7a6d-42c7-9a7e-61dd99267eda","order":3,"chinese":"症状是从什么时候开始的？","pinyin":"zhèng zhuàng shì cóng shén me shí hòu kāi shǐ de","english":"When did the symptoms start?","audioUrl":null},{"id":"c519007a-f31e-42be-b5a8-f7a40f56e524","order":4,"chinese":"前天下午。","pinyin":"qián tiān xià wǔ","english":"The day before yesterday afternoon.","audioUrl":null},{"id":"63aecaa8-1940-49ea-91c8-513693aaad91","order":5,"chinese":"我先帮你量一下体温。","pinyin":"wǒ xiān bāng nǐ liáng yí xià tǐ wēn","english":"Let me take your temperature first.","audioUrl":null},{"id":"c0ae5cfd-a3ba-44cd-9947-3cc2d1841223","order":6,"chinese":"三十八度，你在发烧。","pinyin":"sān shí bā dù nǐ zài fā shāo","english":"Thirty-eight degrees, you have a fever.","audioUrl":null},{"id":"81abe34e-a0b1-45d6-95cb-d1a4caee13ff","order":7,"chinese":"难怪我有点全身酸痛。","pinyin":"nán guài wǒ yóu diǎn quán shēn suān tòng","english":"No wonder I feel a bit sore all over.","audioUrl":null},{"id":"dfdf4be1-d317-4f37-883e-f029dc639a83","order":8,"chinese":"把嘴张大，让我看一下。","pinyin":"bǎ zuǐ zhāng dà ràng wǒ kàn yí xià","english":"Open your mouth wide, let me take a look.","audioUrl":null},{"id":"c848bf57-6e29-4743-b00b-0984ddfc5d4d","order":9,"chinese":"你的喉咙有点发炎。你是得流感了。","pinyin":"nǐ de hóu lóng yóu diǎn fā yán nǐ shì dé liú gǎn le","english":"Your throat is a bit inflamed. You have the flu.","audioUrl":null},{"id":"ac7e5619-92bd-4771-b6af-fb3847c7cc75","order":10,"chinese":"很严重吗？","pinyin":"hěn yán zhòng ma","english":"Is it serious?","audioUrl":null},{"id":"97c26c5b-259c-4a3e-91e3-774a550d1670","order":11,"chinese":"没什么大问题。你有对什么药物过敏吗？","pinyin":"méi shén me dà wèn tí nǐ yǒu duì shén me yào wù guò mǐn ma","english":"It''s not a big problem. Are you allergic to any medication?","audioUrl":null},{"id":"a5b0334c-3b6c-4dca-bb8b-07626ae14ee6","order":12,"chinese":"好，我给你开点抗病毒药。","pinyin":"hǎo wǒ gěi nǐ kāi diǎn kàng bìng dú yào","english":"Okay, I''ll prescribe you some antiviral medication.","audioUrl":null},{"id":"97917517-d7e4-4fe6-b919-5a957677cc63","order":13,"chinese":"每天服用两次，每次两颗。","pinyin":"měi tiān fú yòng liǎng cì měi cì liǎng kē","english":"Take it twice a day, two pills each time.","audioUrl":null},{"id":"d1c744cd-666d-4232-9410-bb54ed2430ec","order":14,"chinese":"空腹或是饭后服用都可以。","pinyin":"kōng fù huò shì fàn hòu fú yòng dōu ké yǐ","english":"You can take it on an empty stomach or after meals.","audioUrl":null},{"id":"07ee2730-f5da-417f-b33b-c59c544bfac7","order":15,"chinese":"好的，谢谢。这个药有副作用吗？","pinyin":"hǎo de xiè xiè zhè ge yào yǒu fù zuò yòng ma","english":"Okay, thank you. Does this medicine have any side effects?","audioUrl":null},{"id":"75442f59-0bc4-49a1-88d9-8e7091a39e9d","order":16,"chinese":"如果出现轻微恶心和晕眩的情况，不用太担心。","pinyin":"rú guǒ chū xiàn qīng wēi ě xīn hé yūn xuàn de qíng kuàng bú yòng tài dān xīn","english":"If you experience mild nausea and dizziness, don''t worry too much.","audioUrl":null},{"id":"580d8c65-5ae8-4a6e-996e-1decb5da4971","order":17,"chinese":"如果服用后严重不适，请立即停药。","pinyin":"rú guǒ fú yòng hòu yán zhòng bú shì qǐng lì jí tíng yào","english":"If you feel seriously unwell after taking it, stop taking it immediately.","audioUrl":null},{"id":"0280f65f-e5f1-4dd8-91e4-60fefffbfc40","order":18,"chinese":"明白了。要多久才能好？","pinyin":"míng bái le yào duō jiǔ cái néng hǎo","english":"Got it. How long will it take to recover?","audioUrl":null},{"id":"5a71691f-8e71-483e-baaa-965ddd4c7abb","order":19,"chinese":"按时吃药，多休息，多喝水，","pinyin":"àn shí chī yào duō xiū xi duō hē shuǐ","english":"Take the medicine on time, rest more, and drink plenty of water.","audioUrl":null},{"id":"163425f5-3caa-416a-9c99-c7be17001a1f","order":20,"chinese":"应该不到一个星期就好了。","pinyin":"yīng gāi bú dào yí gè xīng qī jiù hǎo le","english":"You should be fine in less than a week.","audioUrl":null},{"id":"8ec75ecf-a0aa-4647-9cb6-135af43545f1","order":21,"chinese":"知道了，谢谢医生。","pinyin":"zhī dào le xiè xiè yī shēng","english":"Got it, thank you doctor.","audioUrl":null},{"id":"6d16d2a5-d49a-4540-b3b7-df751ddf6e30","order":22,"chinese":"每年这个时候都是流感季，","pinyin":"měi nián zhè ge shí hòu dōu shì liú gǎn jì","english":"Every year around this time is flu season.","audioUrl":null},{"id":"b16bcf80-df41-450f-a84a-b23f77b3b7ae","order":23,"chinese":"我建议你每年施打流感疫苗，","pinyin":"wǒ jiàn yì nǐ měi nián shī dǎ liú gǎn yì miáo","english":"I recommend getting the flu vaccine annually,","audioUrl":null},{"id":"cbf86643-be65-4e1e-8b95-5931a47f5ebb","order":24,"chinese":"这样可以保护自己和家人。","pinyin":"zhè yàng ké yǐ bǎo hù zì jǐ hé jiā rén","english":"so you can protect yourself and your family.","audioUrl":null},{"id":"39a44d1b-8d13-4426-88ed-a6b53ac600a0","order":25,"chinese":"明白，谢谢你的建议。","pinyin":"míng bái xiè xiè nǐ de jiàn yì","english":"Got it, thank you for the suggestion.","audioUrl":null},{"id":"4b37d7c9-6670-4acd-ba07-eea2762786f6","order":26,"chinese":"请到外面的窗口缴费和取药。","pinyin":"qǐng dào wài miàn de chuāng kǒu jiǎo fèi hé qǔ yào","english":"Please go to the window outside to pay and get your medicine.","audioUrl":null},{"id":"fa6df6dd-3569-450a-9559-c42ce0c8efce","order":27,"chinese":"祝你早日康复。","pinyin":"zhù nǐ zǎo rì kāng fù","english":"Wish you a speedy recovery.","audioUrl":null}]}'::jsonb,
    "updated_at" = now()
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - advanced'
      AND m."title" ILIKE '%cm school%'
      AND m."title" ILIKE '%doctor%'
  );

-- Talking to Family About Mental Health (22 sentences)
UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"f1fe31b4-1f5b-4b0c-8f37-edf429e5eeeb","order":0,"chinese":"爸妈，最近我的状态不是很好，","pinyin":"bà mā zuì jìn wǒ de zhuàng tài bú shì hěn hǎo","english":"Dad, Mom, lately I haven''t been feeling well.","audioUrl":null},{"id":"f3fd30fa-1143-4ee6-a2e1-c08c5e0503d2","order":1,"chinese":"有时候会觉得很焦虑，甚至提不起劲做任何事情。","pinyin":"yǒu shí hòu huì jué de hěn jiāo lǜ shèn zhì tí bù qǐ jìn zuò rèn hé shì qíng","english":"Sometimes I feel very anxious and can''t bring myself to do anything.","audioUrl":null},{"id":"a528dd3e-2dc7-452c-a9c7-5eeb9a4a6dde","order":2,"chinese":"我觉得我可能需要一些帮助。","pinyin":"wǒ jué de wǒ kě néng xū yào yì xiē bāng zhù","english":"I think I might need some help.","audioUrl":null},{"id":"5e2c6c26-e397-4d25-89f2-389e491f9a96","order":3,"chinese":"怎么会这样？是不是工作太忙，压力太大？","pinyin":"zěn me huì zhè yàng shì bu shì gōng zuò tài máng yā lì tài dà","english":"How could this happen? Is it because you''re too busy at work and under too much pressure?","audioUrl":null},{"id":"ea4d4d2f-3d9d-4e49-910f-4dfda0b7a66d","order":4,"chinese":"即使不忙的时候，我也感觉不到快乐，","pinyin":"jí shǐ bù máng de shí hòu wǒ yě gǎn jué bú dào kuài lè","english":"Even when I''m not busy, I don''t feel happy.","audioUrl":null},{"id":"c9568daa-925a-48f9-bb75-f09c8ebac262","order":5,"chinese":"甚至觉得整个人都被压得喘不过气来。","pinyin":"shèn zhì jué de zhěng gè rén dōu bèi yā dé chuǎn bú guò qì lái","english":"I even feel like I''m suffocating under the pressure.","audioUrl":null},{"id":"d14ca4a8-64cb-4cdd-bc0d-7252b603e3d5","order":6,"chinese":"那你有没有跟朋友聊过？","pinyin":"nà nǐ yǒu méi yǒu gēn péng yǒu liáo guò","english":"Have you talked to your friends about this?","audioUrl":null},{"id":"77d1d668-c884-4e15-bdac-a125af3a5ae4","order":7,"chinese":"有，但效果不是很明显。","pinyin":"yǒu dàn xiào guǒ bú shì hěn míng xiǎn","english":"Yes, but it hasn''t really helped.","audioUrl":null},{"id":"d52ebb1a-3081-45b6-8e33-8a00df01bba5","order":8,"chinese":"我觉得这种感觉已经影响到我的生活了，","pinyin":"wǒ jué de zhè zhǒng gǎn jué yǐ jīng yíng xiǎng dào wǒ de shēng huó le","english":"I think this feeling is already affecting my life,","audioUrl":null},{"id":"68759982-8b6c-48a8-bc7a-32c4f661b63a","order":9,"chinese":"或许需要专业的心理咨询。","pinyin":"huò xǔ xū yào zhuān yè de xīn lǐ zī xún","english":"and I might need professional psychological counseling.","audioUrl":null},{"id":"c5ca5270-165c-4a91-82f3-a390614acebf","order":10,"chinese":"心理咨询？那不是给有心理疾病的人去的吗？","pinyin":"xīn lǐ zī xún nà bú shì gěi yǒu xīn lǐ jí bìng de rén qù de ma","english":"Psychological counseling? Isn''t that for people with mental illnesses?","audioUrl":null},{"id":"5471e694-295b-421c-91c3-95dc98866436","order":11,"chinese":"你应该没那么严重吧？","pinyin":"nǐ yīng gāi méi nà me yán zhòng ba","english":"You shouldn''t be that serious, right?","audioUrl":null},{"id":"bd083684-a7c6-4cb2-9851-9d858e9b0a89","order":12,"chinese":"其实心理咨询不只是针对心理疾病，","pinyin":"qí shí xīn lǐ zī xún bù zhǐ shì zhēn duì xīn lǐ jí bìng","english":"Actually, psychological counseling isn''t just for mental illnesses.","audioUrl":null},{"id":"fd07463d-2fb3-430a-bfc7-56806ca1192d","order":13,"chinese":"它也可以帮助我们处理情绪和压力。","pinyin":"tā yě ké yǐ bāng zhù wǒ men chú lǐ qíng xù hé yā lì","english":"It can also help us handle emotions and stress.","audioUrl":null},{"id":"1ce28c94-9cf5-4a43-b441-bcc980f39845","order":14,"chinese":"我觉得这就像身体不舒服要看医生一样，","pinyin":"wǒ jué de zhè jiù xiàng shēn tǐ bù shū fú yào kàn yī shēng yí yàng","english":"I think it''s like seeing a doctor when you''re physically unwell —","audioUrl":null},{"id":"174cc337-2399-4726-8edd-33536cb3130f","order":15,"chinese":"心理健康也是需要重视的。","pinyin":"xīn lǐ jiàn kāng yě shì xū yào zhòng shì de","english":"mental health needs attention too.","audioUrl":null},{"id":"4d336763-32fb-4b7f-9b95-70995c97c1b2","order":16,"chinese":"我们只是担心你，怕你把问题想得太复杂。","pinyin":"wǒ men zhǐ shì dān xīn nǐ pà nǐ bǎ wèn tí xiǎng dé tài fù zá","english":"We''re just worried about you and afraid you''re overthinking the problem.","audioUrl":null},{"id":"abc21345-ae8a-4225-b0b2-463b96cca88d","order":17,"chinese":"如果你觉得这样有帮助，我们当然支持你。","pinyin":"rú guǒ nǐ jué de zhè yàng yǒu bāng zhù wǒ men dāng rán zhī chí nǐ","english":"If you think it will help, of course we''ll support you.","audioUrl":null},{"id":"301f6705-174f-4e50-8e9c-13553b987124","order":18,"chinese":"谢谢你们的理解和支持。","pinyin":"xiè xiè nǐ men de lí jiě hé zhī chí","english":"Thank you for your understanding and support.","audioUrl":null},{"id":"14e8b4dc-ec61-4f0a-8c63-af63da7ea63c","order":19,"chinese":"我会好好照顾自己，也会和你们保持沟通。","pinyin":"wǒ huì háo hǎo zhào gù zì jǐ yě huì hé nǐ men bǎo chí gōu tōng","english":"I''ll take good care of myself and keep communicating with you.","audioUrl":null},{"id":"4692b3ff-1738-4157-91da-5b2809770cf6","order":20,"chinese":"如果有需要，我再跟你们商量。","pinyin":"rú guǒ yǒu xū yào wǒ zài gēn nǐ men shāng liáng","english":"If there''s anything I need, I''ll discuss it with you again.","audioUrl":null},{"id":"13818c33-7d9c-4145-84c1-95efc4d30813","order":21,"chinese":"好，记住无论发生什么事，我们永远在你身边。","pinyin":"hǎo jì zhù wú lùn fā shēng shén me shì wǒ men yóng yuǎn zài nǐ shēn biān","english":"Okay, remember that no matter what happens, we''ll always be here for you.","audioUrl":null}]}'::jsonb,
    "updated_at" = now()
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - advanced'
      AND m."title" ILIKE '%cm school%'
      AND m."title" ILIKE '%mental health%'
  );

-- Conversations About Money (17 sentences)
UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"8fff4a8a-07e9-4611-bda5-a28a02917a11","order":0,"chinese":"最近我开始用理财 APP 记账，","pinyin":"zuì jìn wǒ kāi shǐ yòng lǐ cái jì zhàng","english":"Recently, I started using a personal finance app to track my expenses.","audioUrl":null},{"id":"bc8e258a-7502-4852-9a81-5442f5c9e51f","order":1,"chinese":"才发现出去吃饭花了这么多钱！","pinyin":"cái fā xiàn chū qù chī fàn huā le zhè me duō qián","english":"I was shocked to find out how much I spend on eating out!","audioUrl":null},{"id":"75d3a53c-47cd-4d20-97b7-94737b3e4f61","order":2,"chinese":"我之前也是这样。","pinyin":"wǒ zhī qián yě shì zhè yàng","english":"I was the same before.","audioUrl":null},{"id":"7f80c18f-c01e-45fc-a9a7-6d55838da657","order":3,"chinese":"后来我设定了月度预算，现在控制得好多了。","pinyin":"hòu lái wǒ shè dìng le yuè dù yù suàn xiàn zài kòng zhì dé hǎo duō le","english":"Later, I set a monthly budget, and now I have much better control.","audioUrl":null},{"id":"2601ae92-7414-493a-b9a6-eb1cdbf7ae88","order":4,"chinese":"你是怎么做的？","pinyin":"nǐ shì zěn me zuò de","english":"How did you do it?","audioUrl":null},{"id":"a873c93c-6195-40dd-abff-95c0b0766323","order":5,"chinese":"我总是看到喜欢的东西就忍不住买。","pinyin":"wǒ zǒng shì kàn dào xǐ huan de dōng xi jiù rěn bú zhù mǎi","english":"I can''t resist buying things I like when I see them.","audioUrl":null},{"id":"ddcde0e8-f032-4114-b502-a0def725046f","order":6,"chinese":"我把收入分成几部分：","pinyin":"wǒ bǎ shōu rù fēn chéng jǐ bù fen","english":"I divide my income into a few parts:","audioUrl":null},{"id":"bfce20aa-5d3b-4ea3-a005-5a50692c57ee","order":7,"chinese":"百分之三十存起来，","pinyin":"bǎi fēn zhī sān shí cún qǐ lái","english":"30% is saved,","audioUrl":null},{"id":"4b4f230a-0d5f-4846-823b-daac3d8bb039","order":8,"chinese":"剩下的百分之七十我会花在日常开销、娱乐和投资上。","pinyin":"shèng xià de bǎi fēn zhī qī shí wǒ huì huā zài rì cháng kāi xiāo yú lè hé tóu zī shàng","english":"and the remaining 70% is spent on daily expenses, entertainment, and investments.","audioUrl":null},{"id":"436f2310-fc5a-42fb-b720-a24ef596791d","order":9,"chinese":"刚开始存不了那么多没关系，","pinyin":"gāng kāi shǐ cún bù le nà me duō méi guān xì","english":"It''s okay if you can''t save that much at the beginning.","audioUrl":null},{"id":"4813f44c-2d7d-402f-8306-35ace1b5de60","order":10,"chinese":"哪怕是百分之五或十也可以。","pinyin":"nǎ pà shì bǎi fēn zhī wǔ huò shí yě ké yǐ","english":"Even 5% or 10% is fine.","audioUrl":null},{"id":"03e7d877-0245-4c13-b43c-d0a67b1b5f4d","order":11,"chinese":"重点是养成“先存后花”的习惯。","pinyin":"zhòng diǎn shì yǎng chéng xiān cún hòu huā de xí guàn","english":"The key is to develop the habit of \"saving first, spending later.\"","audioUrl":null},{"id":"25480fec-5d9b-4e96-9531-9592f234999e","order":12,"chinese":"那你是怎么投资的？风险大吗？","pinyin":"nà nǐ shì zěn me tóu zī de fēng xiǎn dà ma","english":"How do you invest? Is it risky?","audioUrl":null},{"id":"d2eaa320-9ee9-45eb-9c98-5b5c345514e5","order":13,"chinese":"风险确实存在，所以记得先研究，不要盲目跟风。","pinyin":"fēng xiǎn què shí cún zài suó yǐ jì de xiān yán jiū bú yào máng mù gēn fēng","english":"There''s definitely risk, so make sure to research first and don''t blindly follow trends.","audioUrl":null},{"id":"0b7baa06-757f-4d66-b87d-9bf23710c895","order":14,"chinese":"你也可以通过分散投资来降低风险。","pinyin":"nǐ yě ké yǐ tōng guò fēn sàn tóu zī lái jiàng dī fēng xiǎn","english":"You can also reduce risk by diversifying your investments.","audioUrl":null},{"id":"738dbe25-c824-4016-b37d-73ff5719168b","order":15,"chinese":"听起来你对存钱和投资很有心得。","pinyin":"tīng qǐ lái nǐ duì cún qián hé tóu zī hěn yǒu xīn dé","english":"It sounds like you have a lot of experience with saving and investing.","audioUrl":null},{"id":"489cd56c-f17b-46bc-ba54-5d987b9c2004","order":16,"chinese":"是的，我认为理财能让我们拥有理想的生活品质。","pinyin":"shì de wǒ rèn wéi lǐ cái néng ràng wǒ men yōng yǒu lí xiǎng de shēng huó pǐn zhì","english":"Yes, I think financial management allows us to have the quality of life we desire.","audioUrl":null}]}'::jsonb,
    "updated_at" = now()
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - advanced'
      AND m."title" ILIKE '%cm school%'
      AND m."title" ILIKE '%money%'
  );

-- Giving Advice (16 sentences)
UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"9a5a27a0-2e84-44e7-a907-9674525b47fb","order":0,"chinese":"最近我一直在想要不要辞掉现在的工作。","pinyin":"zuì jìn wǒ yì zhí zài xiǎng yào bú yào cí diào xiàn zài de gōng zuò","english":"Recently, I''ve been thinking about whether I should quit my current job.","audioUrl":null},{"id":"657d3eea-3c92-47ea-bc01-173ada6ef1be","order":1,"chinese":"你为什么会有这个念头？","pinyin":"nǐ wèi shén me huì yǒu zhè ge niàn tou","english":"Why do you have this thought?","audioUrl":null},{"id":"83c564f0-e9b2-4b82-9ce6-15cef42ae6cf","order":2,"chinese":"我对上班已经没有什么热情了，","pinyin":"wǒ duì shàng bān yǐ jīng méi yǒu shén me rè qíng le","english":"I''ve lost passion for my job,","audioUrl":null},{"id":"efa6c5a1-1447-4d1a-a8ee-d99065c29e6d","order":3,"chinese":"但又怕辞职后找不到更好的工作。","pinyin":"dàn yòu pà cí zhí hòu zhǎo bú dào gèng hǎo de gōng zuò","english":"but I''m afraid I won''t find a better job after quitting.","audioUrl":null},{"id":"c1cc29c3-f6e1-4608-8124-43024920d72b","order":4,"chinese":"我懂你的感受。做这个决定确实很难。","pinyin":"wǒ dǒng nǐ de gǎn shòu zuò zhè ge jué dìng què shí hěn nán","english":"I understand how you feel. It''s really tough to make this decision.","audioUrl":null},{"id":"5b598a42-d625-4dc3-9a89-c3c8119699dd","order":5,"chinese":"你觉得目前的工作对你的长期目标有帮助吗？","pinyin":"nǐ jué de mù qián de gōng zuò duì nǐ de cháng qī mù biāo yǒu bāng zhù ma","english":"Do you think your current job helps with your long-term goals?","audioUrl":null},{"id":"219b4151-a2db-4d33-885b-ed4ea57ef3ee","order":6,"chinese":"坦白说，帮助不大。","pinyin":"tǎn bái shuō bāng zhù bù dà","english":"Honestly, not much.","audioUrl":null},{"id":"6d58ab5b-e59d-4328-aaef-0695b4043cba","order":7,"chinese":"我更想做一些创意类的工作，","pinyin":"wǒ gèng xiǎng zuò yì xiē chuàng yì lèi de gōng zuò","english":"I want to do more creative work,","audioUrl":null},{"id":"842e016f-1d5a-485b-86fd-0bef0c3bd101","order":8,"chinese":"但我现在每天都在做重复的事。","pinyin":"dàn wǒ xiàn zài měi tiān dōu zài zuò chóng fù de shì","english":"but now I''m just doing repetitive tasks every day.","audioUrl":null},{"id":"128fe907-c6cb-4a03-9ac3-05a875ff5086","order":9,"chinese":"那你现在的存款足够让你离职吗？","pinyin":"nà nǐ xiàn zài de cún kuǎn zú gòu ràng nǐ lí zhí ma","english":"Do you have enough savings to allow you to quit your job now?","audioUrl":null},{"id":"d48b95c0-b635-41e0-9c91-364a86c2ed50","order":10,"chinese":"我现在的存款只能维持三个月左右，不太保险。","pinyin":"wǒ xiàn zài de cún kuǎn zhǐ néng wéi chí sān gè yuè zuǒ yòu bú tài báo xiǎn","english":"I only have enough savings to last about three months. It''s not very secure.","audioUrl":null},{"id":"9cfd5bfc-0bf6-433d-b41b-f411ad83247c","order":11,"chinese":"那不如先给自己设定一个过渡计划，","pinyin":"nà bù rú xiān gěi zì jǐ shè dìng yí gè guò dù jì huà","english":"Then how about setting a transition plan for yourself?","audioUrl":null},{"id":"251ae75a-464d-44b9-abed-769e5f88e279","order":12,"chinese":"比如存够六到十二个月的生活费，","pinyin":"bǐ rú cún gòu liù dào shí èr gè yuè de shēng huó fèi","english":"For example, save enough to cover six to twelve months of living expenses.","audioUrl":null},{"id":"f21c326e-d13f-43b8-bbee-0f751b5df19f","order":13,"chinese":"这样即使辞职，生活压力也不会太大。","pinyin":"zhè yàng jí shǐ cí zhí shēng huó yā lì yě bú huì tài dà","english":"That way, even if you quit, you won''t feel too much pressure.","audioUrl":null},{"id":"2f4986bd-73a7-44a5-83de-bd88bb187306","order":14,"chinese":"听起来很实际，你真是太理性了！","pinyin":"tīng qǐ lái hěn shí jì nǐ zhēn shì tài lǐ xìng le","english":"That sounds practical. You''re really rational!","audioUrl":null},{"id":"fca9c87e-15a0-412f-9718-a17ae04c6683","order":15,"chinese":"谢谢你，我会好好考虑这个建议。","pinyin":"xiè xiè nǐ wǒ huì háo hǎo kǎo lǜ zhè ge jiàn yì","english":"Thank you, I''ll seriously consider this suggestion.","audioUrl":null}]}'::jsonb,
    "updated_at" = now()
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - advanced'
      AND m."title" ILIKE '%cm school%'
      AND m."title" ILIKE '%advice%'
  );

-- Talking about values in a relationship (12 sentences)
UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"c840972e-8650-4c58-ae7c-37555fe5375a","order":0,"chinese":"我觉得我们的价值观有点不太一样。","pinyin":"wǒ jué de wǒ men de jià zhí guān yóu diǎn bú tài yí yàng","english":"I feel like our values are a bit different.","audioUrl":null},{"id":"d870c46d-f4f7-4228-a982-b628db4e5c2a","order":1,"chinese":"你指的是哪方面的价值观呢？","pinyin":"nǐ zhǐ de shì nǎ fāng miàn de jià zhí guān ne","english":"What do you mean, specifically?","audioUrl":null},{"id":"5490a558-8e37-4504-b271-167e9f6e48f4","order":2,"chinese":"我觉得诚实和开放对我们的关系很重要，","pinyin":"wǒ jué de chéng shí hé kāi fàng duì wǒ men de guān xì hěn zhòng yào","english":"I think honesty and openness are really important for our relationship.","audioUrl":null},{"id":"e52b724d-562c-4064-a8b7-989cdec4dd4f","order":3,"chinese":"这是我最基本的价值观之一。","pinyin":"zhè shì wǒ zuì jī běn de jià zhí guān zhī yī","english":"It''s one of my core values.","audioUrl":null},{"id":"73c94dec-3418-41a0-bf50-7f173daf3354","order":4,"chinese":"我明白你的感受。","pinyin":"wǒ míng bái nǐ de gǎn shòu","english":"I understand how you feel.","audioUrl":null},{"id":"020b5a6c-a971-4653-8285-0f4373d58f06","order":5,"chinese":"我承认有时候我会选择在某些小事上隐瞒或者保留一些信息。","pinyin":"wǒ chéng rèn yǒu shí hòu wǒ huì xuǎn zé zài mǒu xiē xiǎo shì shàng yǐn mán huò zhě bǎo liú yì xiē xìn xī","english":"I admit, sometimes I choose to withhold or hide certain things, especially small ones.","audioUrl":null},{"id":"664661a3-6551-4360-9850-0fd41fd94965","order":6,"chinese":"我希望我们能建立互信，","pinyin":"wǒ xī wàng wǒ men néng jiàn lì hù xìn","english":"I hope we can build trust,","audioUrl":null},{"id":"b9b0175f-ae93-4b32-b9b3-41da9816d9e3","order":7,"chinese":"这样就可以避免误解或矛盾越来越大。","pinyin":"zhè yàng jiù ké yǐ bì miǎn wù jiě huò máo dùn yuè lái yuè dà","english":"so we can avoid misunderstandings or growing conflicts.","audioUrl":null},{"id":"15097cbc-bcd5-410c-bb8a-9fc9ce8cb243","order":8,"chinese":"我明白了，我很高兴你跟我分享你的顾虑。","pinyin":"wǒ míng bái le wǒ hěn gāo xìng nǐ gēn wǒ fēn xiǎng nǐ de gù lǜ","english":"I understand, and I''m glad you''re sharing your concerns with me.","audioUrl":null},{"id":"c56c4e37-ffa9-49dc-b089-c9dec0e5a83b","order":9,"chinese":"谢谢你聆听和理解。","pinyin":"xiè xiè nǐ líng tīng hé lí jiě","english":"Thank you for listening and understanding.","audioUrl":null},{"id":"51dc2339-c4d9-4b65-b0bd-afac42355f50","order":10,"chinese":"其实我们的价值观并不一定要完全一致，","pinyin":"qí shí wǒ men de jià zhí guān bìng bù yí dìng yào wán quán yí zhì","english":"Our values don''t have to be exactly the same,","audioUrl":null},{"id":"12b88747-0a30-4646-a183-0fa729c3b520","order":11,"chinese":"但我希望我们能在彼此的差异中找到平衡。","pinyin":"dàn wǒ xī wàng wǒ men néng zài bí cǐ de chā yì zhōng zhǎo dào píng héng","english":"but I hope we can find a balance in our differences.","audioUrl":null}]}'::jsonb,
    "updated_at" = now()
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - advanced'
      AND m."title" ILIKE '%cm school%'
      AND m."title" ILIKE '%relationship%'
  );

-- Family Values (14 sentences)
UPDATE "course_library_lessons" AS l
SET "lesson_type" = 'listening_practice',
    "content" = '{"description":"Listen to each sentence and type what you hear.","sentences":[{"id":"ee94f2b7-8feb-4b46-8c83-1fd230673997","order":0,"chinese":"妈，我想老实告诉你，我和 Michelle 不打算生孩子。","pinyin":"mā wǒ xiǎng lǎo shí gào sù nǐ wǒ hé bù dǎ suàn shēng hái zi","english":"Mom, I want to be honest with you. Michelle and I have decided not to have kids.","audioUrl":null},{"id":"30307c36-4bb3-4a8a-ba3a-a9258f964335","order":1,"chinese":"没有孩子，将来怎么办？","pinyin":"méi yǒu hái zi jiāng lái zěn me bàn","english":"No kids? What will you do in the future?","audioUrl":null},{"id":"28efba63-7a9b-4fe7-a91b-a355b4a8b7f8","order":2,"chinese":"你们老了谁照顾你们？","pinyin":"nǐ men lǎo le shuí zhào gù nǐ men","english":"Who will take care of you when you''re old?","audioUrl":null},{"id":"1d3a7d79-a949-4317-88a9-b9717c4ed6ce","order":3,"chinese":"我明白你的出发点，","pinyin":"wǒ míng bái nǐ de chū fā diǎn","english":"I understand where you''re coming from,","audioUrl":null},{"id":"ef314063-e74d-4ff4-bb32-a5ed92763937","order":4,"chinese":"但我和 Michelle 都觉得生孩子不应该是为了养儿防老的。","pinyin":"dàn wǒ hé dōu jué de shēng hái zi bù yīng gāi shì wèi le yǎng ér fáng lǎo de","english":"but Michelle and I feel that having kids shouldn''t just be about ensuring we''re taken care of in old age.","audioUrl":null},{"id":"97e6dbc6-a018-4220-a4dc-2367dc37cc20","order":5,"chinese":"而且养育孩子在情感和经济上都要负很大的责任。","pinyin":"ér qiě yǎng yù hái zi zài qíng gǎn hé jīng jì shàng dōu yào fù hěn dà de zé rèn","english":"Raising kids comes with a lot of emotional and financial responsibility.","audioUrl":null},{"id":"26f43dd1-2db3-4c5c-b70d-eb8d7cb94587","order":6,"chinese":"我们不希望让孩子和自己都承担不必要的压力。","pinyin":"wǒ men bù xī wàng ràng hái zi hé zì jǐ dōu chéng dān bú bì yào de yā lì","english":"We don''t want to put unnecessary pressure on ourselves or the child.","audioUrl":null},{"id":"decf987a-b489-4583-a61d-2781c0a14333","order":7,"chinese":"你们将来肯定会后悔的。","pinyin":"nǐ men jiāng lái kěn dìng huì hòu huǐ de","english":"You''re definitely going to regret this in the future.","audioUrl":null},{"id":"d4e87d43-9c54-484e-be88-5e9343b01d77","order":8,"chinese":"我们已经充分考虑过了，","pinyin":"wǒ men yǐ jīng chōng fèn kǎo lǜ guò le","english":"We''ve thought this through,","audioUrl":null},{"id":"da83447a-9aba-43ad-acbe-689dfdd8d801","order":9,"chinese":"并不是草率地做这个决定的。","pinyin":"bìng bú shì cǎo shuài dì zuò zhè ge jué dìng de","english":"and it''s not a decision we made lightly.","audioUrl":null},{"id":"37f32700-23c3-4105-aeb2-c0371c234a80","order":10,"chinese":"我希望在这件事上能有更多的空间做自己的选择，","pinyin":"wǒ xī wàng zài zhè jiàn shì shàng néng yǒu gèng duō de kōng jiān zuò zì jǐ de xuǎn zé","english":"I just hope we can have the space to make our own choices on this,","audioUrl":null},{"id":"5107915c-8619-48c2-b91f-201b893b38bb","order":11,"chinese":"而不是为了满足你们的期望来改变自己的人生。","pinyin":"ér bú shì wèi le mǎn zú nǐ men de qī wàng lái gǎi biàn zì jǐ de rén shēng","english":"rather than changing our lives just to meet your expectations.","audioUrl":null},{"id":"b4e6d196-1f37-4724-b6e7-dbd76fa80345","order":12,"chinese":"我可能需要多一点时间来理解你们的决定。","pinyin":"wǒ kě néng xū yào duō yì diǎn shí jiān lái lí jiě nǐ men de jué dìng","english":"I may need more time to understand your decision.","audioUrl":null},{"id":"2784362b-4e5e-4b01-8c70-17a3c2160698","order":13,"chinese":"可是无论如何我都希望你们能够幸福。","pinyin":"kě shì wú lùn rú hé wǒ dōu xī wàng nǐ men néng gòu xìng fú","english":"But no matter what, I just want you both to be happy.","audioUrl":null}]}'::jsonb,
    "updated_at" = now()
WHERE l."lesson_type" = 'audio'
  AND l."deleted_at" IS NULL
  AND l."module_id" IN (
    SELECT m."id"
    FROM "course_library_modules" m
    JOIN "course_library_courses" c ON c."id" = m."course_id"
    WHERE m."deleted_at" IS NULL
      AND c."deleted_at" IS NULL
      AND lower(trim(c."title")) = 'the canto to mando blueprint - advanced'
      AND m."title" ILIKE '%cm school%'
      AND m."title" ILIKE '%family values%'
  );
